# ===== 创建字典 =====
student = {
    'name': 'Alice',
    'age': 25,
    'scores': [85, 90, 78, 92],
    'is_active': True
}

# ===== 读取 =====
print(student['name'])           # 'Alice'
print(student.get('grade'))      # None（安全访问）
print(student.get('grade', 'N/A'))  # 'N/A'（默认值）

# ===== 修改/新增 =====
student['age'] = 26             # 修改
student['city'] = 'Beijing'     # 新增

# ===== 遍历 =====
for key, value in student.items():
    print(f'{key}: {value}')

